503	// ── Institutional knowledge fallback ─────────────────────────
504	async function fetchInstitutionalFallback(
505	    contextType: string
506	): Promise<ScoredAction[]> {
507	    // JOIN dim_actions so we get real action names, not just IDs
508	    const { data, error } = await supabase
509	        .from('dim_institutional_knowledge')
510	        .select(`
511	            action_id,
512	            avg_success_rate,
513	            sample_count,
514	            context_type,
515	            dim_actions!inner(action_id, action_name, action_category)
516	        `)
517	        .eq('context_type', contextType)
518	        .order('avg_success_rate', { ascending: false });
519	
520	    if (error || !data || data.length === 0) return [];
521	
522	    return data.map((row: any): ScoredAction => ({
523	        action_id: row.action_id,
524	        action_name: row.dim_actions?.action_name ?? row.action_id,
525	        action_category: row.dim_actions?.action_category ?? 'unknown',
526	        composite_score: Math.round((row.avg_success_rate ?? 0) * 10000) / 10000,
527	        confidence: 0,  // no per-customer data yet
528	        trend_delta: null,
529	        trend: 'stable',
530	        total_attempts: row.sample_count ?? 0,
531	        is_cold_start: true,
532	        is_low_sample: (row.sample_count ?? 0) < 3,
533	        recommendation: toRecommendation(row.avg_success_rate ?? 0, false),
534	    }));
535	}
536	
537	// ── Global fallback (Tier 3) ──────────────────────────────────
538	// Used when no context-specific priors exist for the given issue_type.
539	// Queries context_type = 'global' — always non-empty after migration 066.
540	// After this tier, ranked_actions is never empty.
541	async function fetchGlobalFallback(): Promise<ScoredAction[]> {
542	    const { data, error } = await supabase
543	        .from('dim_institutional_knowledge')
544	        .select(`
545	            action_id,
546	            avg_success_rate,
547	            sample_count,
548	            context_type,
549	            dim_actions!inner(action_id, action_name, action_category)
550	        `)
551	        .eq('context_type', 'global')
552	        .order('avg_success_rate', { ascending: false });
553	
554	    if (error || !data || data.length === 0) return [];
555	
556	    return data.map((row: any): ScoredAction => ({
557	        action_id: row.action_id,
558	        action_name: row.dim_actions?.action_name ?? row.action_id,
559	        action_category: row.dim_actions?.action_category ?? 'unknown',
560	        composite_score: Math.round((row.avg_success_rate ?? 0) * 10000) / 10000,
561	        confidence: 0,
562	        trend_delta: null,
563	        trend: 'stable',
564	        total_attempts: row.sample_count ?? 0,
565	        is_cold_start: true,
566	        is_low_sample: false,
567	        recommendation: toRecommendation(row.avg_success_rate ?? 0, false),
568	    }));
569	}
570	
571	// ── Public API ────────────────────────────────────────────────
572	export async function getScores(
573	    customerId: string,
574	    contextId: string,
575	    contextType?: string,
576	    forceRefresh = false,
577	    contextMatch: number | null = null
578	): Promise<ScoringResult> {
579	    const key = cacheKey(customerId, contextId);
580	    const cached = scoreCache.get(key);
581	
582	    // Serve from cache if valid and not forced
583	    if (!forceRefresh && cached && cached.expires_at > Date.now()) {
584	        const top = cached.scores[0];
585	        return {
586	            ranked_actions: cached.scores,
587	            top_action: top,
588	            should_escalate: top?.composite_score < ESCALATION_SCORE,
589	            cold_start: top?.is_cold_start ?? false,
590	            context_id: contextId,
591	            customer_id: customerId,
592	            view_refreshed_at: null,
593	            served_from_cache: true,
594	        };
595	    }
596	
597	    // Fetch from materialized view
598	    const { scores: rawScores, view_refreshed_at } = await fetchScoresFromDB(customerId, contextId);
599	
600	    let scoredActions: ScoredAction[];
601	    let isColdStart = false;
602	
603	    if (rawScores.length === 0 || rawScores.every(r => r.confidence < MIN_CONFIDENCE)) {
604	        isColdStart = true;
605	
606	        // Tier 2: context-specific institutional priors
607	        let fallback = contextType
608	            ? await fetchInstitutionalFallback(contextType)
609	            : [];
610	
611	        // Tier 3: global fallback — ranked_actions is NEVER empty after migration 066
612	        if (fallback.length === 0) {
613	            console.info(
614	                `[scoring] No priors for context_type="${contextType ?? 'none'}". ` +
615	                `Using global fallback.`
616	            );
617	            fallback = await fetchGlobalFallback();
618	        }
619	
620	        scoredActions = fallback;
621	    } else {
622	        const contextLatencyP75 = computeContextLatencyBaselineP75(rawScores);
623	
624	        const lowSampleRows = rawScores.filter(r => (r.total_attempts ?? 0) < 20);
625	        const ipsMap = lowSampleRows.length > 0
626	            ? await withTimeout(
627	                batchFetchIPSSignals(lowSampleRows.map(r => r.action_id), customerId),
628	                2000
629	            ) ?? new Map<string, number>()
630	            : new Map<string, number>();
631	
632	        const clusterPriors = await withTimeout(
633	            fetchClusterPriors(customerId, rawScores.map((row) => row.action_id)),
634	            2000,
635	        ) ?? new Map<string, ClusterPrior>();
636	
637	        scoredActions = rawScores.map((row): ScoredAction => {
638	            const score = computeCompositeScore(
639	                row,
640	                contextMatch,
641	                ipsMap.get(row.action_id) ?? null,
642	                contextLatencyP75,
643	            );
644	            const blendedScore = blendWithClusterPrior(
645	                score,
646	                row,
647	                clusterPriors.get(row.action_id),
648	            );
649	            return {
650	                action_id: row.action_id,
651	                action_name: row.action_name,
652	                action_category: row.action_category,
653	                composite_score: Math.round(blendedScore * 10000) / 10000,
654	                confidence: row.total_attempts < 3 ? Math.min(row.confidence, 0.25) : row.confidence,
655	                trend_delta: row.trend_delta,
656	                trend: trendLabel(row.trend_delta),
657	                total_attempts: row.total_attempts,
658	                is_cold_start: false,
659	                is_low_sample: row.total_attempts < 3,
660	                recommendation: toRecommendation(blendedScore, false),
661	            };
662	        }).sort((a, b) => b.composite_score - a.composite_score);
663	    }
664	
665	    // Store in cache
666	    scoreCache.set(key, { scores: scoredActions, expires_at: Date.now() + CACHE_TTL_MS });
667	    if (scoreCache.size > MAX_CACHE_ENTRIES) {
668	        const oldestKey = scoreCache.keys().next().value as string | undefined;
669	        if (oldestKey) scoreCache.delete(oldestKey);
670	    }
671	
672	    const top = scoredActions[0] ?? null;
673	
674	    return {
675	        ranked_actions: scoredActions,
676	        top_action: top,
677	        should_escalate: !top || top.composite_score < ESCALATION_SCORE,
678	        cold_start: isColdStart,
679	        context_id: contextId,
680	        customer_id: customerId,
681	        view_refreshed_at: view_refreshed_at,
682	        served_from_cache: false,
683	    };
684	}
685	
686	// Export constants for tests
687	export { MIN_CONFIDENCE, ESCALATION_SCORE, W_SUCCESS, W_CONF, W_TREND, W_SALIENCE, W_RECENCY, W_LATENCY };
688	
689	/**
690	 * Compute the effective score for an outcome.
691	 * If outcome_score is provided and valid (0.0–1.0), use it.
692	 * Otherwise fall back to binary: success=1.0, failure=0.0.
693	 *
694	 * This mirrors the DB-level COALESCE(outcome_score, success::FLOAT)
695	 * used in mv_action_scores, but for application-level logic.
696	 */
697	export function computeEffectiveScore(
698	    success: boolean,
699	    outcomeScore?: number
700	): number {
701	    if (outcomeScore !== undefined && outcomeScore >= 0.0 && outcomeScore <= 1.0) {
702	        return outcomeScore;
703	    }
704	    return success ? 1.0 : 0.0;
705	}
