1	/**
2	 * Layerinfinite — lib/policy-engine.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Explore / Exploit / Escalate decision tree.
5	 *
6	 * This file contains ZERO database calls. It is a pure function
7	 * that takes ranked actions + trust + config and returns a
8	 * deterministic policy decision.
9	 *
10	 * randomFn is injectable for testing (deterministic in tests).
11	 * ══════════════════════════════════════════════════════════════
12	 */
13	
14	import { ScoredAction } from './scoring.js';
15	
16	// ── Input types ──────────────────────────────────────────────
17	
18	export interface AgentTrustScore {
19	    trust_score: number;       // 0.0–1.0
20	    trust_status: 'trusted' | 'probation' | 'sandbox' | 'suspended' | 'new';
21	    consecutive_failures: number;
22	}
23	
24	export interface CustomerPolicyConfig {
25	    risk_tolerance: 'conservative' | 'balanced' | 'aggressive';
26	    escalation_score: number;  // below this → escalate (default 0.2)
27	    exploration_rate: number;  // epsilon for epsilon-greedy (default 0.05)
28	    min_confidence: number;  // below this → cold start (default 0.3)
29	}
30	
31	export interface PolicyDecision {
32	    policy: 'exploit' | 'explore' | 'escalate' | 'SANDBOX' | 'abstain';
33	    reason: string;
34	    selectedAction: string | null;
35	    explorationTarget: string | null;
36	    human_review_required?: boolean;
37	    sandbox_message?: string;
38	    abstain_message?: string;
39	}
40	
41	// ── Default config (used when customer config is missing) ────
42	
43	export const DEFAULT_POLICY_CONFIG: CustomerPolicyConfig = {
44	    risk_tolerance: 'balanced',
45	    escalation_score: 0.20,
46	    exploration_rate: 0.05,
47	    min_confidence: 0.30,
48	};
49	
50	/**
51	 * Fallback trust used when agent_trust_scores row is absent.
52	 *
53	 * INVARIANT: This fallback should never be reached in normal operation.
54	 * The fn_init_agent_trust() DB trigger (migration 058) inserts a
55	 * trust_status='new' row at agent creation time (ON CONFLICT DO NOTHING).
56	 * If this fallback fires in production, it signals a trigger failure
57	 * or manual DB manipulation - the logs will show 'agent_new_no_history'
58	 * reason in the policy decision, which is a detectable signal.
59	 *
60	 * trust_score: 0 - not 0.5. A missing row has no real signal.
61	 * trust_status: 'new' - routes to Rule 1.3 exploration, matching
62	 * the DB default. Never 'probation' - that implies real history.
63	 */
64	export const DEFAULT_TRUST: AgentTrustScore = {
65	    trust_score: 0,
66	    trust_status: 'new',
67	    consecutive_failures: 0,
68	};
69	
70	// ── Decision tree ────────────────────────────────────────────
71	
72	export function getPolicyDecision(
73	    params: {
74	        rankedActions: ScoredAction[];
75	        agentTrust: AgentTrustScore | null | undefined;
76	        customerConfig: CustomerPolicyConfig;
77	        coldStartActive: boolean;
78	    },
79	    randomFn: () => number = Math.random
80	): PolicyDecision {
81	    // ── FIX: null guard — use DEFAULT_TRUST if trust not available ──
82	    const agentTrust = params.agentTrust ?? DEFAULT_TRUST;
83	    const { rankedActions, customerConfig, coldStartActive } = params;
84	
85	    // ── Rule 1: Suspended agent → always escalate ─────────────
86	    if (agentTrust.trust_status === 'suspended') {
87	        return {
88	            policy: 'escalate',
89	            reason: 'agent_suspended',
90	            selectedAction: null,
91	            explorationTarget: null,
92	            human_review_required: true,
93	        };
94	    }
95	
96	    const topAction = rankedActions[0];
97	
98	    // ── Rule 1.3: New agent (no history) → force explore ──────
99	    // A 'new' agent has zero outcomes. Exploiting an uninformed prior would
100	    // be misleading. Force exploration to gather real signal first.
101	    if (agentTrust.trust_status === 'new') {
102	        const target = rankedActions.length > 0
103	            ? [...rankedActions].sort((a, b) => a.total_attempts - b.total_attempts)[0]
104	            : null;
105	        return {
106	            policy: 'explore',
107	            reason: 'agent_new_no_history',
108	            selectedAction: null,
109	            explorationTarget: target?.action_id ?? null,
110	        };
111	    }
112	
113	    // ── Rule 1.4: Sandbox agent → flag for review but execute top action
114	    if (agentTrust.trust_status === 'sandbox') {
115	        return {
116	            policy: 'SANDBOX',
117	            reason: 'agent_in_sandbox_probation',
118	            selectedAction: topAction?.action_id ?? null,
119	            explorationTarget: null,
120	            human_review_required: true,
121	            sandbox_message: 'Agent is in sandbox mode. ' +
122	                'All actions will execute but require human review. ' +
123	                `Trust score: ${agentTrust.trust_score.toFixed(3)}. ` +
124	                `Threshold to exit sandbox: 0.3`,
125	        };
126	    }
127	
128	    // ── Rule 2: Cold start OR all confidence < threshold ──────
129	    const allLowConfidence = rankedActions.length > 0 &&
130	        rankedActions.every(a => a.confidence < customerConfig.min_confidence);
131	
132	    if (coldStartActive || allLowConfidence) {
133	        // Suggest the action with the lowest sample count (most exploration value)
134	        const target = rankedActions.length > 0
135	            ? [...rankedActions].sort((a, b) => a.total_attempts - b.total_attempts)[0]
136	            : null;
137	
138	        return {
139	            policy: 'explore',
140	            reason: 'cold_start',
141	            selectedAction: null,
142	            explorationTarget: target?.action_id ?? null,
143	        };
144	    }
145	
146	    if (!topAction) {
147	        return {
148	            policy: 'escalate',
149	            reason: 'no_actions_available',
150	            selectedAction: null,
151	            explorationTarget: null,
152	            human_review_required: true,
153	        };
154	    }
155	
156	    const topScore = topAction.composite_score;
157	    const topConf = topAction.confidence;
158	
159	    // ── Rule 2.5: Ambiguous low-separation rankings → abstain ───
160	    // When top actions are statistically too close, return explicit abstain
161	    // rather than forcing exploration/exploitation.
162	    const secondAction = rankedActions.length > 1 ? rankedActions[1] : null;
163	    if (secondAction) {
164	        const scoreGap = Math.abs(topAction.composite_score - secondAction.composite_score);
165	        const bothInAmbiguousBand =
166	            topAction.composite_score >= 0.40
167	            && topAction.composite_score <= 0.70
168	            && secondAction.composite_score >= 0.40
169	            && secondAction.composite_score <= 0.70;
170	        const bothConfidentEnough =
171	            Math.min(topAction.confidence, secondAction.confidence) >= customerConfig.min_confidence;
172	
173	        if (scoreGap <= 0.03 && bothInAmbiguousBand && bothConfidentEnough) {
174	            return {
175	                policy: 'abstain',
176	                reason: 'ambiguous_low_separation',
177	                selectedAction: null,
178	                explorationTarget: null,
179	                human_review_required: true,
180	                abstain_message:
181	                    'Top actions are statistically indistinguishable. ' +
182	                    `gap=${scoreGap.toFixed(4)} between ${topAction.action_name} and ${secondAction.action_name}. ` +
183	                    'Escalate or gather additional outcomes before auto-execution.',
184	            };
185	        }
186	    }
187	
188	    // ── Rule 3: Conservative + top > 0.8 → always exploit ─────
189	    if (customerConfig.risk_tolerance === 'conservative' && topScore > 0.8) {
190	        return {
191	            policy: 'exploit',
192	            reason: 'conservative_high_score',
193	            selectedAction: topAction.action_id,
194	            explorationTarget: null,
195	        };
196	    }
197	
198	    // ── Rule 4: High score + high confidence → epsilon-greedy ─
199	    if (topScore > 0.85 && topConf > 0.8) {
200	        const roll = randomFn();
201	        if (roll < customerConfig.exploration_rate) {
202	            // Explore: pick 2nd action (or lowest-sample action)
203	            const exploreTarget = rankedActions.length > 1
204	                ? rankedActions[1]
205	                : topAction;
206	
207	            return {
208	                policy: 'explore',
209	                reason: 'epsilon_greedy_explore',
210	                selectedAction: null,
211	                explorationTarget: exploreTarget.action_id,
212	            };
213	        }
214	        return {
215	            policy: 'exploit',
216	            reason: 'epsilon_greedy_exploit',
217	            selectedAction: topAction.action_id,
218	            explorationTarget: null,
219	        };
220	    }
221	
222	    // ── Rule 5: Medium score (0.5–0.85) → exploit with probability
223	    if (topScore >= 0.5 && topScore <= 0.85) {
224	        const exploitProbability = topConf;  // confidence × 100%
225	        const roll = randomFn();
226	
227	        if (roll < exploitProbability) {
228	            return {
229	                policy: 'exploit',
230	                reason: 'confidence_weighted_exploit',
231	                selectedAction: topAction.action_id,
232	                explorationTarget: null,
233	            };
234	        }
235	        // Explore the 2nd-best action
236	        const exploreTarget = rankedActions.length > 1
237	            ? rankedActions[1]
238	            : topAction;
239	        return {
240	            policy: 'explore',
241	            reason: 'confidence_weighted_explore',
242	            selectedAction: null,
243	            explorationTarget: exploreTarget.action_id,
244	        };
245	    }
246	
247	    // ── Rule 6: All scores < escalation threshold → escalate ──
248	    if (rankedActions.every(a => a.composite_score < customerConfig.escalation_score)) {
249	        return {
250	            policy: 'escalate',
251	            reason: 'no_reliable_action',
252	            selectedAction: null,
253	            explorationTarget: null,
254	        };
255	    }
256	
257	    // ── Rule 7: Default → explore 2nd action ──────────────────
258	    const fallbackTarget = rankedActions.length > 1
259	        ? rankedActions[1]
260	        : topAction;
261	
262	    return {
263	        policy: 'explore',
264	        reason: 'default_exploration',
265	        selectedAction: null,
266	        explorationTarget: fallbackTarget.action_id,
267	    };
268	}
