1	/**
2	 * Layerinfinite — lib/simulation/tier2.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Tier 2 simulation using LightGBM model.
5	 * Available after 200 episodes and model training.
6	 * Returns prediction intervals, not just point estimates.
7	 *
8	 * Multi-step aggregation:
9	 *   - Single-step → direct prediction
10	 *   - Multi-step → geometric mean (penalizes long sequences)
11	 *   - Intervals widen with sequence length
12	 * ══════════════════════════════════════════════════════════════
13	 */
14	
15	import { predictOutcome, loadWorldModel } from './world-model.js';
16	import type { SequencePrediction, SimulationRequest } from './types.js';
17	
18	/**
19	 * Predict outcome for a proposed sequence using Tier 2 model.
20	 *
21	 * For multi-step sequences, predict each step independently
22	 * and combine using conservative aggregation:
23	 *   - Predicted outcome = geometric mean of per-step probabilities
24	 *     (penalizes long sequences appropriately)
25	 *   - Confidence interval widens with sequence length
26	 */
27	export async function tier2Predict(
28	  request: SimulationRequest,
29	  contextFreq: number,
30	): Promise<SequencePrediction | null> {
31	  const model = await loadWorldModel(request.customerId);
32	  if (!model) return null;
33	
34	  const sequence = [
35	    ...request.episodeHistory,
36	    ...request.proposedSequence,
37	  ];
38	
39	  // Predict each step in the proposed sequence
40	  const stepPredictions = await Promise.all(
41	    request.proposedSequence.map(async (action, stepIdx) => {
42	      const history = sequence.slice(
43	        0,
44	        request.episodeHistory.length + stepIdx,
45	      );
46	
47	      return predictOutcome(request.customerId, action, history, request.contextHash, contextFreq);
48	    }),
49	  );
50	
51	  // If any action in the sequence is unknown to the model,
52	  // return null (fall back to Tier 1)
53	  if (stepPredictions.some((p) => p === null)) {
54	    return null;
55	  }
56	
57	  const predictions = stepPredictions as NonNullable<
58	    (typeof stepPredictions)[0]
59	  >[];
60	
61	  // Aggregate multi-step predictions
62	  let aggregateQ50: number;
63	  let aggregateQ025: number;
64	  let aggregateQ975: number;
65	
66	  if (predictions.length === 1) {
67	    aggregateQ50 = predictions[0]!.q50;
68	    aggregateQ025 = predictions[0]!.q025;
69	    aggregateQ975 = predictions[0]!.q975;
70	  } else {
71	    // Multi-step: geometric mean penalizes long sequences
72	    const product = predictions.reduce((acc, p) => acc * p.q50, 1.0);
73	    aggregateQ50 = Math.pow(product, 1 / predictions.length);
74	
75	    // Interval widens: outer predictions bound the aggregate
76	    aggregateQ025 = Math.min(...predictions.map((p) => p.q025));
77	    aggregateQ975 = Math.max(...predictions.map((p) => p.q975));
78	  }
79	
80	  const width = aggregateQ975 - aggregateQ025;
81	
82	  return {
83	    actions: [...request.episodeHistory, ...request.proposedSequence],
84	    predictedOutcome: Math.round(aggregateQ50 * 10000) / 10000,
85	    outcomeIntervalLow: Math.round(aggregateQ025 * 10000) / 10000,
86	    outcomeIntervalHigh: Math.round(aggregateQ975 * 10000) / 10000,
87	    confidenceWidth: Math.round(width * 10000) / 10000,
88	    confidence: Math.max(0.0, 1.0 - width),
89	    predictedResolution:
90	      aggregateQ50 >= 0.7 ? aggregateQ50 : aggregateQ50 * 0.8,
91	    predictedSteps: request.proposedSequence.length,
92	    betterThanProposed: false,
93	  };
94	}
