1	/**
2	 * Layerinfinite — lib/simulation/world-model.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Loads, caches, and evaluates the Tier 2 LightGBM world model.
5	 * Model trained in Python, serialized as JSON trees, stored in
6	 * world_model_artifacts. Evaluated in TypeScript via tree walking.
7	 *
8	 * Cache: module-level, 30 min TTL, one per edge function instance.
9	 * ══════════════════════════════════════════════════════════════
10	 */
11	
12	import { supabase } from '../supabase.js';
13	import type {
14	  WorldModelArtifact,
15	  LGBMTree,
16	  WorldModelPrediction,
17	} from './types.js';
18	
19	// ── Module-level cache (keyed by customer_id for multi-tenant isolation) ─
20	const modelCache = new Map<string, WorldModelArtifact>();
21	// In-flight loading promises — prevents cache stampede under
22	// concurrent MCTS rollouts. Multiple callers for the same
23	// customerId await the same DB fetch instead of each making
24	// their own.
25	const modelLoadingPromises = new Map<string, Promise<WorldModelArtifact | null>>();
26	const modelCacheLoadedAt = new Map<string, Date>();
27	const canaryCache = new Map<string, WorldModelArtifact>();
28	const canaryCacheLoadedAt = new Map<string, Date>();
29	// In-flight sentinels: prevent cache stampede when TTL expires.
30	// Multiple concurrent callers (e.g. 10 MCTS rollouts in a batch)
31	// share the same Promise instead of each firing a DB query.
32	const canaryLoadingPromise = new Map<string, Promise<WorldModelArtifact | null>>();
33	const CACHE_TTL_MS = 30 * 60 * 1000; // 30 minutes
34	
35	/**
36	 * Load the active Tier 2 world model for a specific customer.
37	 * Caches per customer_id for edge function instance lifetime.
38	 * Returns null if no trained model exists yet for this customer.
39	 */
40	export async function loadWorldModel(customerId: string): Promise<WorldModelArtifact | null> {
41	  const cached = modelCache.get(customerId);
42	  const loadedAt = modelCacheLoadedAt.get(customerId);
43	  if (cached && loadedAt && Date.now() - loadedAt.getTime() < CACHE_TTL_MS) {
44	    return cached;
45	  }
46	
47	  const inflight = modelLoadingPromises.get(customerId);
48	  if (inflight) return inflight;
49	
50	  const loadPromise = (async (): Promise<WorldModelArtifact | null> => {
51	    try {
52	      const { data, error } = await supabase
53	        .from('world_model_artifacts')
54	        .select('model_data, trained_at, version, training_episodes')
55	        .eq('tier', 2)
56	        .eq('is_active', true)
57	        .eq('customer_id', customerId)
58	        .maybeSingle();
59	
60	      if (error || !data) {
61	        modelCache.delete(customerId);
62	        return null;
63	      }
64	
65	      const model = data.model_data as WorldModelArtifact;
66	      model.trained_at = data.trained_at;
67	      model.version = data.version;
68	      model.training_episodes = data.training_episodes;
69	      model.is_canary = false;
70	      model.canary_traffic_pct = 0;
71	
72	      modelCache.set(customerId, model);
73	      modelCacheLoadedAt.set(customerId, new Date());
74	      return model;
75	    } catch (err) {
76	      modelCache.delete(customerId);
77	      console.error('[world-model] loadWorldModel failed:', (err as Error).message);
78	      return null;
79	    } finally {
80	      modelLoadingPromises.delete(customerId);
81	    }
82	  })();
83	
84	  modelLoadingPromises.set(customerId, loadPromise);
85	  return loadPromise;
86	}
87	
