141	/**
142	 * Invalidate the model cache for a specific customer (production and canary).
143	 * Called when a new model is activated. Pass customerId to clear one tenant,
144	 * or omit to clear all cached models.
145	 */
146	export function invalidateModelCache(customerId?: string): void {
147	  if (customerId) {
148	    modelCache.delete(customerId);
149	    modelCacheLoadedAt.delete(customerId);
150	    modelLoadingPromises.delete(customerId);
151	    canaryCache.delete(customerId);
152	    canaryCacheLoadedAt.delete(customerId);
153	    canaryLoadingPromise.delete(customerId);
154	  } else {
155	    modelCache.clear();
156	    modelCacheLoadedAt.clear();
157	    modelLoadingPromises.clear();
158	    canaryCache.clear();
159	    canaryCacheLoadedAt.clear();
160	    canaryLoadingPromise.clear();
161	  }
