163	
164	/**
165	 * Evaluate a single LightGBM tree on the feature vector.
166	 * Walks the tree from root to leaf and returns the leaf value.
167	 *
168	 * LightGBM tree encoding:
169	 *   - Internal nodes have non-negative indices
170	 *   - Leaf nodes are encoded as negative: leaf = -(index + 1)
171	 */
172	export function evaluateTree(
173	  tree: LGBMTree,
174	  features: number[],
175	): number {
176	  let nodeIndex = 0; // start at root (index 0)
177	  const maxIterations = (tree.split_feature.length + 1) * 2;
178	  let iterations = 0;
179	
180	  while (nodeIndex >= 0) {
181	    iterations++;
182	    if (iterations > maxIterations) {
183	      console.error(
184	        `[world-model] evaluateTree: max iterations exceeded. ` +
185	        `Possible cycle in tree structure. ` +
186	        `split_feature.length=${tree.split_feature.length}, ` +
187	        `nodeIndex=${nodeIndex}. Returning 0.`
188	      );
189	      return 0;
190	    }
191	
192	    const featureIndex = tree.split_feature[nodeIndex]!;
193	    const threshold = tree.threshold[nodeIndex] as number;
194	    const leftChild = tree.left_child[nodeIndex]!;
195	    const rightChild = tree.right_child[nodeIndex]!;
196	
197	    const featureValue = features[featureIndex] ?? 0;
198	
199	    if (featureValue <= threshold) {
200	      nodeIndex = leftChild;
201	    } else {
202	      nodeIndex = rightChild;
203	    }
204	
205	    // Negative index means leaf node
206	    if (nodeIndex < 0) {
207	      const leafIndex = -(nodeIndex + 1);
208	      return tree.leaf_value[leafIndex] ?? 0;
209	    }
210	  }
211	
212	  return 0; // fallback (should not reach here with valid tree)
213	}
214	
215	/**
216	 * Run full LightGBM ensemble prediction.
217	 * Sums all trees with learning rate scaling.
218	 */
219	export function predictEnsemble(
220	  trees: LGBMTree[],
221	  features: number[],
222	  learningRate: number,
223	): number {
224	  return trees.reduce(
225	    (sum, tree) => sum + evaluateTree(tree, features) * learningRate,
226	    0,
227	  );
228	}
229	
230	/**
231	 * Build feature vector for the world model.
232	 * Feature order MUST match training-time feature order.
233	 *
234	 * Features:
235	 *   [0] action_encoded      — integer from action_encoding map
236	 *   [1] episode_position    — step number (0-based)
237	 *   [2] prev_action_1       — previous action integer (-1 if none)
238	 *   [3] prev_action_2       — 2nd previous (-1 if none)
239	 *   [4] prev_action_3       — 3rd previous (-1 if none)
240	 *   [5] context_type_freq   — how often this context appears (0–1)
241	 *   [6] hour_sin            — sin(hour/24 * 2π) cyclical
242	 *   [7] hour_cos            — cos(hour/24 * 2π) cyclical
243	 *   [8] dow_sin             — sin(dayOfWeek/7 * 2π) cyclical
244	 *   [9] dow_cos             — cos(dayOfWeek/7 * 2π) cyclical
245	 */
246	export function buildFeatures(
247	  model: WorldModelArtifact,
248	  actionName: string,
249	  episodeHistory: string[],
250	  _contextHash: string,
251	  contextFreq: number,
252	): number[] {
253	  const actionEnc = model.action_encoding[actionName] ?? -1;
254	  const now = new Date();
255	  const hour = now.getUTCHours();
256	  const dow = now.getUTCDay();
257	
258	  const prevActions = episodeHistory.slice(-3).reverse();
259	  const prev1 = model.action_encoding[prevActions[0] ?? ''] ?? -1;
260	  const prev2 = model.action_encoding[prevActions[1] ?? ''] ?? -1;
261	  const prev3 = model.action_encoding[prevActions[2] ?? ''] ?? -1;
262	
263	  return [
264	    actionEnc,
265	    episodeHistory.length,
266	    prev1,
267	    prev2,
268	    prev3,
269	    contextFreq,
270	    Math.sin((hour / 24) * 2 * Math.PI),
271	    Math.cos((hour / 24) * 2 * Math.PI),
272	    Math.sin((dow / 7) * 2 * Math.PI),
273	    Math.cos((dow / 7) * 2 * Math.PI),
274	  ];
275	}
276	
277	/**
278	 * Predict outcome for a given action in given context.
279	 * Returns q50 (median), q025 (lower), q975 (upper), and model_source.
280	 * Routes a percentage of traffic to the canary model when one is deployed.
281	 * Returns null if action not in model encoding.
282	 */
283	export async function predictOutcome(
284	  customerId: string,
285	  actionName: string,
286	  episodeHistory: string[],
287	  contextHash: string,
288	  contextFreq: number = 0.5,
289	): Promise<WorldModelPrediction | null> {
290	  // Load production model first (always required as fallback)
291	  const productionModel = await loadWorldModel(customerId);
292	  if (!productionModel) return null;
293	
294	  // Check if a canary model is deployed and should serve this request
295	  const canaryModel = await loadCanaryModel(customerId);
296	  const useCanary =
297	    canaryModel !== null &&
298	    canaryModel.canary_traffic_pct > 0 &&
299	    Math.random() * 100 < canaryModel.canary_traffic_pct;
300	
301	  const model = useCanary ? canaryModel! : productionModel;
302	  const modelSource: 'production' | 'canary' = useCanary ? 'canary' : 'production';
303	
304	  if (!(actionName in model.action_encoding)) {
305	    // If canary doesn't know this action, fall back to production
306	    if (useCanary && actionName in productionModel.action_encoding) {
307	      return runPrediction(productionModel, actionName, episodeHistory, contextHash, contextFreq, 'production');
308	    }
309	    return null;
310	  }
311	
312	  return runPrediction(model, actionName, episodeHistory, contextHash, contextFreq, modelSource);
313	}
314	
315	function runPrediction(
316	  model: WorldModelArtifact,
317	  actionName: string,
318	  episodeHistory: string[],
319	  contextHash: string,
320	  contextFreq: number,
321	  modelSource: 'production' | 'canary',
322	): WorldModelPrediction {
323	  const features = buildFeatures(model, actionName, episodeHistory, contextHash, contextFreq);
324	
325	  const q50 = predictEnsemble(model.q50.trees, features, model.learning_rate);
326	  const q025 = predictEnsemble(model.q025.trees, features, model.learning_rate);
327	  const q975 = predictEnsemble(model.q975.trees, features, model.learning_rate);
328	
329	  const clamp = (v: number) => Math.max(0.0, Math.min(1.0, v));
330	
331	  if (modelSource === 'canary') {
332	    console.info(
333	      `[world-model] canary prediction — action=${actionName} ` +
334	      `version=${model.version} traffic_pct=${model.canary_traffic_pct}`
335	    );
336	  }
337	
338	  return {
339	    q50: clamp(q50),
340	    q025: clamp(q025),
341	    q975: clamp(q975),
342	    width: clamp(q975) - clamp(q025),
343	    model_source: modelSource,
344	  };
345	}
