1	/**
2	 * Layerinfinite — lib/drift-detector.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Proactive embedding drift detection.
5	 *
6	 * Maintains a reference corpus of canonical text samples with
7	 * known embeddings under the current model. On each check, a
8	 * random subset is re-embedded and compared against the stored
9	 * reference vectors.
10	 *
11	 * If mean cosine similarity drops below DRIFT_THRESHOLD (0.995),
12	 * drift is detected — indicating the embedding provider has
13	 * silently updated model weights. All stored vectors are flagged
14	 * as potentially_stale.
15	 *
16	 * Triggered via: POST /v1/admin/embedding-drift/check
17	 * ══════════════════════════════════════════════════════════════
18	 */
19	
20	import { supabase } from './supabase.js';
21	import { generateEmbedding, cosineSimilarity } from './context-embed.js';
22	
23	function parseFiniteNumber(raw: string | undefined, fallback: number): number {
24	    const parsed = Number(raw);
25	    return Number.isFinite(parsed) ? parsed : fallback;
26	}
27	
28	function parsePositiveInt(raw: string | undefined, fallback: number): number {
29	    const parsed = Number.parseInt(raw ?? '', 10);
30	    return Number.isFinite(parsed) && parsed > 0 ? parsed : fallback;
31	}
32	
33	const DRIFT_THRESHOLD = parseFiniteNumber(process.env.EMBEDDING_DRIFT_THRESHOLD, 0.995);
34	const DRIFT_CHECK_SAMPLE_SIZE = parsePositiveInt(process.env.EMBEDDING_DRIFT_SAMPLE_SIZE, 100);
35	
36	export interface DriftReport {
37	    mean_similarity: number;
38	    min_similarity: number;
39	    sample_size: number;
40	    drift_detected: boolean;
41	    drift_threshold: number;
42	    embedding_model: string;
43	    checked_at: string;
44	    skipped: boolean;
45	    skip_reason?: string;
46	}
47	
48	/**
49	 * Re-embeds a sample of reference corpus entries and compares
50	 * against stored reference vectors to detect silent model drift.
51	 */
52	export async function runDriftDetection(): Promise<DriftReport> {
53	    const embeddingModel = process.env.EMBEDDING_PROVIDER === 'openai'
54	        ? 'text-embedding-3-small'
55	        : 'gte-small';
56	
57	    const checkedAt = new Date().toISOString();
58	
59	    // Load sample from reference corpus for current model
60	    const { data: corpus, error: corpusErr } = await supabase
61	        .from('embedding_reference_corpus')
62	        .select('id, sample_text, reference_vector')
63	        .eq('embedding_model', embeddingModel)
64	        .limit(DRIFT_CHECK_SAMPLE_SIZE * 3); // over-fetch then random-sample
65	
66	    if (corpusErr || !corpus || corpus.length === 0) {
67	        return {
68	            mean_similarity: 1.0,
69	            min_similarity: 1.0,
70	            sample_size: 0,
71	            drift_detected: false,
72	            drift_threshold: DRIFT_THRESHOLD,
73	            embedding_model: embeddingModel,
74	            checked_at: checkedAt,
75	            skipped: true,
76	            skip_reason: corpus?.length === 0
77	                ? 'Reference corpus is empty — populate embedding_reference_corpus first'
78	                : `Corpus query failed: ${corpusErr?.message}`,
79	        };
80	    }
81	
82	    // Random sample
83	    const shuffled = corpus.sort(() => Math.random() - 0.5);
84	    const sample = shuffled.slice(0, Math.min(DRIFT_CHECK_SAMPLE_SIZE, shuffled.length));
85	
86	    const similarities: number[] = [];
87	
88	    for (const entry of sample) {
89	        const freshVector = await generateEmbedding(entry.sample_text);
90	        if (!freshVector) continue;
91	
92	        if (!entry.reference_vector) {
93	            continue;
94	        }
95	
96	        const storedVec = typeof entry.reference_vector === 'string'
97	            ? parseVec(entry.reference_vector)
98	            : (entry.reference_vector as number[]);
99	
100	        if (!storedVec || storedVec.length !== freshVector.length) continue;
101	
102	        try {
103	            const sim = cosineSimilarity(freshVector, storedVec);
104	            similarities.push(sim);
105	        } catch {
106	            // dimension mismatch — indicates model change, counts as severe drift
107	            similarities.push(0);
108	        }
109	    }
110	
111	    if (similarities.length === 0) {
112	        return {
113	            mean_similarity: 1.0,
114	            min_similarity: 1.0,
115	            sample_size: 0,
116	            drift_detected: false,
117	            drift_threshold: DRIFT_THRESHOLD,
118	            embedding_model: embeddingModel,
119	            checked_at: checkedAt,
120	            skipped: true,
121	            skip_reason: 'No valid similarity pairs computed — embedding provider may be unavailable',
122	        };
123	    }
124	
125	    const meanSim = similarities.reduce((a, b) => a + b, 0) / similarities.length;
126	    const minSim = Math.min(...similarities);
127	    const driftDetected = meanSim < DRIFT_THRESHOLD;
128	
129	    // Persist report
130	    const { error: reportErr } = await supabase.from('embedding_drift_reports').insert({
131	        mean_similarity: meanSim,
132	        min_similarity: minSim,
133	        sample_size: similarities.length,
134	        drift_detected: driftDetected,
135	        drift_threshold: DRIFT_THRESHOLD,
136	        embedding_model: embeddingModel,
137	        checked_at: checkedAt,
138	    });
139	    if (reportErr) {
140	        console.warn('[drift-detector] Failed to persist drift report:', reportErr.message);
141	    }
142	
143	    if (driftDetected) {
144	        console.warn(
145	            `[drift-detector] EMBEDDING DRIFT DETECTED — model=${embeddingModel} ` +
146	            `mean_similarity=${meanSim.toFixed(4)} threshold=${DRIFT_THRESHOLD}. ` +
147	            'Stored vectors may be stale. Consider re-embedding dim_contexts.'
148	        );
149	    } else {
150	        console.info(
151	            `[drift-detector] No drift detected — model=${embeddingModel} ` +
152	            `mean_similarity=${meanSim.toFixed(4)} (threshold=${DRIFT_THRESHOLD})`
153	        );
154	    }
155	
156	    return {
157	        mean_similarity: meanSim,
158	        min_similarity: minSim,
159	        sample_size: similarities.length,
160	        drift_detected: driftDetected,
161	        drift_threshold: DRIFT_THRESHOLD,
162	        embedding_model: embeddingModel,
163	        checked_at: checkedAt,
164	        skipped: false,
165	    };
166	}
167	
168	function parseVec(v: string): number[] {
169	    try {
170	        const parsed = v
171	            .replace(/[\[\]]/g, '')
172	            .split(',')
173	            .map((x) => Number(x.trim()));
174	
175	        if (parsed.length === 0 || parsed.some((n) => !Number.isFinite(n))) {
176	            return [];
177	        }
178	
179	        return parsed;
180	    } catch {
181	        return [];
182	    }
183	}
