1	import { supabase } from './supabase.js';
2	
3	export interface BackpropInput {
4	    episode_id: string;
5	    customer_id: string;
6	    final_outcome: number;
7	    gamma?: number;
8	}
9	
10	export interface BackpropResult {
11	    steps_adjusted: number;
12	    episode_id: string;
13	    final_outcome: number;
14	    mv_refresh_triggered: boolean;
15	}
16	
17	export async function backpropagateReward(input: BackpropInput): Promise<BackpropResult> {
18	    const gamma = input.gamma ?? 0.85;
19	
20	    try {
21	        const { data: steps, error } = await supabase
22	            .from('fact_outcomes')
23	            .select('outcome_id, backprop_adjusted')
24	            .eq('session_id', input.episode_id)
25	            .eq('customer_id', input.customer_id)
26	            .order('timestamp', { ascending: true });
27	
28	        if (error || !steps || steps.length === 0) {
29	            return {
30	                steps_adjusted: 0,
31	                episode_id: input.episode_id,
32	                final_outcome: input.final_outcome,
33	                mv_refresh_triggered: false,
34	            };
35	        }
36	
37	        let stepsAdjusted = 0;
38	        const totalSteps = steps.length;
39	
40	        for (let i = 0; i < totalSteps; i++) {
41	            const step = steps[i];
42	
43	            if (step.backprop_adjusted === true) {
44	                continue;  // idempotent
45	            }
46	
47	            // For Temporal Difference decay:
48	            // Calculate penalty distance for preceding steps in identical episode grouping.
49	            // Notice: final_outcome * Math.pow(...) calculates exponential score damping.
50	            // Failures (0.0) evaluate to 0.0 synchronously masking earlier steps identically.
51	            // Success (1.0) evaluations map strictly to geometric curve.
52	            const adjusted = input.final_outcome * Math.pow(gamma, totalSteps - 1 - i);
53	            const roundedAdjusted = Math.round(adjusted * 10000) / 10000;
54	
55	            const { data } = await supabase
56	                .from('fact_outcomes')
57	                .update({
58	                    outcome_score: roundedAdjusted,
59	                    backprop_adjusted: true,
60	                    backprop_episode_id: input.episode_id
61	                })
62	                .eq('outcome_id', step.outcome_id)
63	                .eq('customer_id', input.customer_id)
64	                .select();
65	
66	            if (data && data.length > 0) {
67	                stepsAdjusted++;
68	            }
69	        }
70	
71	        let mvRefreshTriggered = false;
72	        if (stepsAdjusted > 0) {
73	            try {
74	                const { error: refreshErr } = await supabase
75	                    .rpc('refresh_task_action_performance');
76	                if (refreshErr) {
77	                    console.warn(
78	                        '[backprop] MV refresh failed after backprop:',
79	                        refreshErr.message,
80	                        `episode_id=${input.episode_id}`
81	                    );
82	                } else {
83	                    mvRefreshTriggered = true;
84	                    console.info(
85	                        '[backprop] MV refresh triggered after backprop',
86	                        { episode_id: input.episode_id, steps_adjusted: stepsAdjusted }
87	                    );
88	                }
89	            } catch (refreshErr: any) {
90	                console.warn('[backprop] MV refresh threw:', refreshErr.message);
91	            }
92	        }
93	
94	        return {
95	            steps_adjusted: stepsAdjusted,
96	            episode_id: input.episode_id,
97	            final_outcome: input.final_outcome,
98	            mv_refresh_triggered: mvRefreshTriggered,
99	        };
100	
101	    } catch (err) {
102	        console.error('[BackpropReward] Exception:', err);
103	        return {
104	            steps_adjusted: 0,
105	            episode_id: input.episode_id,
106	            final_outcome: input.final_outcome,
107	            mv_refresh_triggered: false,
108	        };
109	    }
110	}
