1	/**
2	 * Layerinfinite — lib/sanitize.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Security utilities to harden JSON payloads against prototype 
5	 * pollution and resource exhaustion (DoS).
6	 * ══════════════════════════════════════════════════════════════
7	 */
8	
9	/**
10	 * Recursively truncates deep objects, strips prototype keys, and limits key count.
11	 * @param input Raw unsanitized JSON input from request body
12	 * @param maxDepth Maximum allowed nesting depth before truncation
13	 * @param maxKeys Maximum number of allowed keys at any single object level
14	 * @param currentDepth Tracks recursion depth internally
15	 */
16	export function sanitizeContext(
17	    input: unknown,
18	    maxDepth = 5,
19	    maxKeys = 50,
20	    currentDepth = 0
21	): Record<string, unknown> {
22	    try {
23	        if (input === null || typeof input !== 'object') {
24	            // Primitive values are inherently safe from prototype pollution and depth issues,
25	            // but the root must return a Record. We wrap primitive roots in an empty object.
26	            // If it's a deep leaf node, we return the primitive, but the signature
27	            // expects Record<string, unknown> at the top level. We use `any` here
28	            // because TypeScript's strict type guard at the return boundary is too narrow 
29	            // for recursive mixed-type traversals without complex discriminated types.
30	            if (currentDepth === 0) return {};
31	            return input as any;
32	        }
33	
34	        if (Array.isArray(input)) {
35	            if (currentDepth >= maxDepth) {
36	                return '[truncated: max depth exceeded]' as any;
37	            }
38	            // Arrays are limited by length (reusing maxKeys for array length limit to prevent memory exhaustion)
39	            const safeArray = input.slice(0, maxKeys).map((item) =>
40	                sanitizeContext(item, maxDepth, maxKeys, currentDepth + 1)
41	            );
42	            return safeArray as any;
43	        }
44	
45	        // Object processing
46	        if (currentDepth >= maxDepth) {
47	            return '[truncated: max depth exceeded]' as any;
48	        }
49	
50	        const safeObj: Record<string, unknown> = {};
51	        const keys = Object.keys(input);
52	
53	        // Truncate keys alphabetically to ensure deterministic stripping
54	        if (keys.length > maxKeys) {
55	            keys.sort();
56	            keys.length = maxKeys;
57	            console.warn(`[sanitize] Object keys truncated from ${Object.keys(input).length} to ${maxKeys}`);
58	        }
59	
60	        for (const key of keys) {
61	            // Strip prototype pollution vectors
62	            if (key === '__proto__' || key === 'constructor' || key === 'prototype') {
63	                continue;
64	            }
65	
66	            // Avoid cyclic references by standard recursion stack, handled implicitly by depth limit
67	            safeObj[key] = sanitizeContext((input as any)[key], maxDepth, maxKeys, currentDepth + 1);
68	        }
69	
70	        return safeObj;
71	    } catch (err) {
72	        // Fail safe: never throw JSON parsing or traversal errors to the event loop
73	        return {};
74	    }
75	}
76	
77	/**
78	 * Trims strings to a maximum length and strips potentially malicious null bytes.
79	 * @param input Raw unsanitized string
80	 * @param maxLength Maximum allowed length
81	 */
82	export function sanitizeString(input: string | undefined | null, maxLength = 1000): string {
83	    if (!input || typeof input !== 'string') return '';
84	    return input.replace(/\0/g, '').substring(0, maxLength);
85	}
