1	/**
2	 * LayerInfinite MCP Server — param-resolver.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Three-Layer Parameter Resolution for auto mode redirects.
5	 *
6	 * When auto mode redirects from action A → action B, parameters
7	 * must be adapted because different actions may require different params.
8	 *
9	 * Layer 1: Shared params carry over (matching field names)
10	 * Layer 2: Action defaults fill gaps (from dim_actions.required_params)
11	 * Layer 3: Missing params returned to agent to fill from its context
12	 * ══════════════════════════════════════════════════════════════
13	 */
14	
15	/** Schema for a single parameter in an action's param definition. */
16	export interface ParamDef {
17	  type: string;
18	  description?: string;
19	  default?: unknown;
20	  required?: boolean;
21	}
22	
23	/** The param schema stored in dim_actions.required_params. */
24	export type ActionParamSchema = Record<string, ParamDef>;
25	
26	export interface ResolvedParams {
27	  /** Fully resolved params ready for execution. */
28	  resolved: Record<string, unknown>;
29	  /** Params that could not be resolved — agent must fill these. */
30	  needed: Record<string, ParamDef>;
31	  /** Whether all required params are resolved. */
32	  fullyResolved: boolean;
33	}
34	
35	/**
36	 * Resolves parameters for a redirected action using the three-layer strategy.
37	 *
38	 * @param originalParams - The params the agent sent for the original action
39	 * @param targetSchema   - The param schema of the target (redirected) action
40	 */
41	export function resolveParams(
42	  originalParams: Record<string, unknown>,
43	  targetSchema: ActionParamSchema | null,
44	): ResolvedParams {
45	  // If target action has no defined schema, pass through original params
46	  if (!targetSchema || Object.keys(targetSchema).length === 0) {
47	    return { resolved: { ...originalParams }, needed: {}, fullyResolved: true };
48	  }
49	
50	  const resolved: Record<string, unknown> = {};
51	  const needed: Record<string, ParamDef> = {};
52	
53	  for (const [paramName, paramDef] of Object.entries(targetSchema)) {
54	    // Layer 1: Shared params — carry over from original if name matches
55	    if (paramName in originalParams) {
56	      resolved[paramName] = originalParams[paramName];
57	      continue;
58	    }
59	
60	    // Layer 2: Action defaults — use default from schema
61	    if (paramDef.default !== undefined) {
62	      resolved[paramName] = paramDef.default;
63	      continue;
64	    }
65	
66	    // Layer 3: Cannot resolve — agent must fill
67	    if (paramDef.required !== false) {
68	      needed[paramName] = paramDef;
69	    }
70	  }
71	
72	  return {
73	    resolved,
74	    needed,
75	    fullyResolved: Object.keys(needed).length === 0,
76	  };
77	}
