1	/**
2	 * LayerInfinite MCP Server — tools/li-fallback.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Recovery tool — registered in assist + auto modes.
5	 * When an action fails, get the next-best action excluding
6	 * already-tried actions (uses EpisodeTracker for loop prevention).
7	 * ══════════════════════════════════════════════════════════════
8	 */
9	
10	import { z } from 'zod';
11	import type { RestClient } from '../rest-client.js';
12	import type { EpisodeTracker } from '../episode-tracker.js';
13	
14	export const LI_FALLBACK_NAME = 'li_fallback';
15	
16	export const LI_FALLBACK_DESCRIPTION =
17	  'Get the next-best action after a failure. Excludes previously tried actions ' +
18	  'to prevent loops. Always call li_log with the result after executing.';
19	
20	export const liFallbackSchema = {
21	  task: z.string().min(1).describe('Same task that failed'),
22	  failed_action: z.string().min(1).describe('The action that just failed'),
23	  error_context: z.string().max(500).optional().describe('Why it failed — helps LI exclude similar actions'),
24	  episode_id: z.string().uuid().optional().describe('Episode ID for tracking tried actions'),
25	};
26	
27	interface ScoresResponse {
28	  ranked_actions: Array<{
29	    action_name: string;
30	    composite_score: number;
31	    confidence: number;
32	    [key: string]: unknown;
33	  }>;
34	  decision_id: string;
35	  [key: string]: unknown;
36	}
37	
38	export function createLiFallbackHandler(client: RestClient, episodeTracker: EpisodeTracker) {
39	  return async (input: z.infer<z.ZodObject<typeof liFallbackSchema>>) => {
40	    const { task, failed_action, error_context, episode_id } = input;
41	    const episodeId = episode_id ?? `ephemeral-${Date.now()}`;
42	
43	    // Mark the failed action as tried (Gap Fix #2)
44	    episodeTracker.markTried(episodeId, failed_action);
45	
46	    // Fetch fresh scores (cache was invalidated by the li_log call)
47	    const result = await client.get<ScoresResponse>('/v1/get-scores', {
48	      issue_type: task,
49	    });
50	
51	    if (!result.ok) {
52	      return {
53	        content: [{
54	          type: 'text' as const,
55	          text: JSON.stringify({
56	            fallback_available: false,
57	            error: result.error.message ?? result.error.error,
58	            tried_actions: Array.from(episodeTracker.getTriedActions(episodeId)),
59	          }),
60	        }],
61	        isError: true,
62	      };
63	    }
64	
65	    const triedActions = episodeTracker.getTriedActions(episodeId);
66	    const ranked = result.data.ranked_actions ?? [];
67	
68	    // Filter out all tried actions
69	    const candidates = ranked.filter(a => !triedActions.has(a.action_name));
70	
71	    if (candidates.length === 0) {
72	      return {
73	        content: [{
74	          type: 'text' as const,
75	          text: JSON.stringify({
76	            fallback_available: false,
77	            reason: 'All available actions have been tried',
78	            tried_actions: Array.from(triedActions),
79	            decision_id: result.data.decision_id,
80	          }),
81	        }],
82	      };
83	    }
84	
85	    const nextBest = candidates[0];
86	    episodeTracker.markTried(episodeId, nextBest.action_name);
87	
88	    return {
89	      content: [{
90	        type: 'text' as const,
91	        text: JSON.stringify({
92	          fallback_available: true,
93	          next_action: nextBest.action_name,
94	          confidence: nextBest.composite_score,
95	          decision_id: result.data.decision_id,
96	          episode_id: episodeId,
97	          tried_actions: Array.from(episodeTracker.getTriedActions(episodeId)),
98	          ...(error_context ? { previous_error: error_context } : {}),
99	        }),
100	      }],
101	    };
102	  };
103	}
