1	/**
2	 * LayerInfinite MCP Server — tools/li-simulate.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Mode-gated. Sequence prediction via the 3-tier simulation engine.
5	 * Maps to POST /v1/simulate on the LI REST API.
6	 *
7	 * The simulate endpoint requires agent_id in the body. Since the
8	 * MCP server authenticates via X-API-Key (which resolves to an agent),
9	 * we pass a placeholder and let the auth middleware resolve it.
10	 * ══════════════════════════════════════════════════════════════
11	 */
12	
13	import { z } from 'zod';
14	import type { RestClient } from '../rest-client.js';
15	
16	export const LI_SIMULATE_NAME = 'li_simulate';
17	
18	export const LI_SIMULATE_DESCRIPTION =
19	  'Simulate a proposed action sequence and predict its outcome. Returns ' +
20	  'success probability, confidence intervals, and alternative sequences.';
21	
22	export const liSimulateSchema = {
23	  task: z.string().min(1).describe('Task context for the simulation'),
24	  proposed_sequence: z.array(z.string().min(1)).min(1).max(5).describe('Ordered list of actions to simulate'),
25	  episode_history: z.array(z.string()).optional().describe('Actions already taken in this episode'),
26	};
27	
28	export function createLiSimulateHandler(client: RestClient) {
29	  return async (input: z.infer<z.ZodObject<typeof liSimulateSchema>>) => {
30	    // The simulate endpoint requires agent_id in the POST body.
31	    // The X-API-Key auth middleware on the REST API sets agent_id in the
32	    // request context. We send 'mcp' as a marker; the auth middleware
33	    // overrides this with the real agent_id from the API key lookup.
34	    const result = await client.post<unknown>('/v1/simulate', {
35	      agent_id: 'mcp',
36	      context: { issue_type: input.task },
37	      proposed_sequence: input.proposed_sequence,
38	      episode_history: input.episode_history ?? [],
39	    });
40	
41	    if (!result.ok) {
42	      return {
43	        content: [{ type: 'text' as const, text: JSON.stringify({ error: result.error.message ?? result.error.error }) }],
44	        isError: true,
45	      };
46	    }
47	
48	    return { content: [{ type: 'text' as const, text: JSON.stringify(result.data) }] };
49	  };
50	}
