1	/**
2	 * LayerInfinite MCP Server — config.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Single source of truth for all environment configuration.
5	 * Validates required vars at startup and exports a frozen config object.
6	 * ══════════════════════════════════════════════════════════════
7	 */
8	
9	export type LIMode = 'recommend' | 'assist' | 'auto';
10	
11	export interface LIConfig {
12	  /** API key for authenticating with the LayerInfinite REST API. */
13	  readonly apiKey: string;
14	  /** Base URL of the LayerInfinite API (no trailing slash). */
15	  readonly baseUrl: string;
16	  /** Operating mode. null = bootstrap (log only). */
17	  readonly mode: LIMode | null;
18	  /** Admin key for gated tools. null = admin tools disabled. */
19	  readonly adminKey: string | null;
20	}
21	
22	const VALID_MODES: ReadonlySet<string> = new Set(['recommend', 'assist', 'auto']);
23	
24	/**
25	 * Reads and validates environment variables.
26	 * Throws immediately if required vars are missing — fail fast at startup.
27	 */
28	export function loadConfig(): LIConfig {
29	  const apiKey = process.env.LAYERINFINITE_API_KEY;
30	  if (!apiKey || apiKey.trim() === '') {
31	    throw new Error(
32	      '[layerinfinite-mcp] LAYERINFINITE_API_KEY is required. ' +
33	      'Get your key from the LayerInfinite dashboard.',
34	    );
35	  }
36	
37	  const baseUrl = (process.env.LAYERINFINITE_BASE_URL ?? 'https://layerinfinite.me').replace(/\/+$/, '');
38	
39	  const rawMode = (process.env.LAYERINFINITE_MODE ?? '').trim().toLowerCase();
40	  let mode: LIMode | null = null;
